import{_ as c,C as u,o as t,c as h,a0 as o,b as n,w as a,a as i,E as s,a1 as d,j as r}from"./chunks/framework.BjpW4enL.js";const y=JSON.parse('{"title":"Leandraft Linter","description":"","frontmatter":{},"headers":[],"relativePath":"projects/leandraft-linter.md","filePath":"projects/leandraft-linter.md"}'),p={name:"projects/leandraft-linter.md"};function m(b,e,A,k,g,_){const l=u("Mermaid");return t(),h("div",null,[e[2]||(e[2]=o('<h1 id="leandraft-linter" tabindex="-1">Leandraft Linter <a class="header-anchor" href="#leandraft-linter" aria-label="Permalink to &quot;Leandraft Linter&quot;">​</a></h1><p>개발 초안(Draft) 및 기술 설계 문서의 서식 불일치, 가이드라인 미준수 사항을 코드 빌드 이전에 자동 검출해주는 텍스트 기반 정적 분석 린터(Linter)입니다.</p><h2 id="📌-status-repository" tabindex="-1">📌 Status &amp; Repository <a class="header-anchor" href="#📌-status-repository" aria-label="Permalink to &quot;📌 Status &amp; Repository&quot;">​</a></h2><ul><li><strong>상태</strong>: <code>Stable</code></li><li><strong>저장소 주소</strong>: <a href="https://github.com/devcy0922/leandraft-linter" target="_blank" rel="noreferrer">GitHub (devcy0922/leandraft-linter)</a></li><li><strong>라이선스</strong>: MIT</li><li><strong>주요 언어</strong>: Rust</li></ul><hr><h2 id="_1-problem" tabindex="-1">1. Problem <a class="header-anchor" href="#_1-problem" aria-label="Permalink to &quot;1. Problem&quot;">​</a></h2><p>소프트웨어 설계를 코드로 옮기기 전 단계에서 기술 설계서(RFC, 아키텍처 초안 마크다운)를 작성하게 됩니다. 이때 각 파트너 엔지니어마다 문서 구조(제목 레벨, 테이블 포맷, 필수 섹션 존재 유무)가 뒤죽박죽이 되거나, 예전 사설 IP 주소나 내부 시스템명 등 민감 정보가 설계서 내에 무방비로 적재되어 깃허브에 푸시되는 휴먼 에러가 빈번하게 발생합니다.</p><h2 id="_2-why-i-built-it" tabindex="-1">2. Why I Built It <a class="header-anchor" href="#_2-why-i-built-it" aria-label="Permalink to &quot;2. Why I Built It&quot;">​</a></h2><p>마크다운 추상 구문 트리(AST) 파서 엔진을 내장한 고속 린터를 구현하여, 로컬 커밋 이전에 개발 초안 설계 문서 내 필수 뼈대 준수 여부를 검사하고, 보안 가이드라인(PII, 사설 주소 대역 노출 금지 등)을 위반하는 단어가 문서에 하드코딩되어 있는지 검증하는 도구로 개발했습니다.</p><h2 id="_3-scope" tabindex="-1">3. Scope <a class="header-anchor" href="#_3-scope" aria-label="Permalink to &quot;3. Scope&quot;">​</a></h2><ul><li>Markdown AST(Abstract Syntax Tree) 파싱을 통한 문서 구조 검사</li><li>PII(개인정보) 및 보안 위험 키워드 정적 블랙리스트 필터링</li><li>필수 RFC 문서 템플릿 색인 준수 여부 자동 채점</li><li>Git pre-commit Hook 연동을 위한 초고속 CLI 바이너리 제공</li></ul><hr><h2 id="_4-architecture" tabindex="-1">4. Architecture <a class="header-anchor" href="#_4-architecture" aria-label="Permalink to &quot;4. Architecture&quot;">​</a></h2>',13)),(t(),n(d,null,{default:a(()=>[s(l,{id:"mermaid-73",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20File%5B%22Architecture%20Draft%20(Markdown)%22%5D%20--%3E%7C1.%20Input%7C%20Parser%5B%22Markdown%20AST%20Parser%20(pulldown-cmark)%22%5D%0A%20%20%20%20subgraph%20Engine%20%5B%22Lingo%20Linter%20Engine%22%5D%0A%20%20%20%20%20%20%20%20Parser%20--%3E%20AST%5B%22AST%20Node%20Stream%22%5D%0A%20%20%20%20%20%20%20%20AST%20--%3E%20Rule1%5B%22Rule%201%3A%20Template%20Structure%20Validator%22%5D%0A%20%20%20%20%20%20%20%20AST%20--%3E%20Rule2%5B%22Rule%202%3A%20Security%20Word%20Filter%20(DLP)%22%5D%0A%20%20%20%20%20%20%20%20AST%20--%3E%20Rule3%5B%22Rule%203%3A%20Dead%20Link%20Checker%22%5D%0A%20%20%20%20end%0A%20%20%20%20Rule1%20%26%20Rule2%20%26%20Rule3%20--%3E%7CAssemble%20Report%7C%20Report%5B%22CLI%20Report%20%26%20Exit%20Code%22%5D%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[i(" Loading... ",-1)])]),_:1})),e[3]||(e[3]=r("hr",null,null,-1)),e[4]||(e[4]=r("h2",{id:"_5-request-flow",tabindex:"-1"},[i("5. Request Flow "),r("a",{class:"header-anchor",href:"#_5-request-flow","aria-label":'Permalink to "5. Request Flow"'},"​")],-1)),(t(),n(d,null,{default:a(()=>[s(l,{id:"mermaid-78",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20autonumber%0A%20%20%20%20participant%20Developer%20as%20Developer%0A%20%20%20%20participant%20Git%20as%20Git%20Repository%0A%20%20%20%20participant%20Linter%20as%20Linter%20CLI%0A%0A%20%20%20%20Developer-%3E%3EGit%3A%20git%20commit%20-m%20%22docs%3A%20add%20architecture%20spec%22%0A%20%20%20%20Git-%3E%3ELinter%3A%20Run%20pre-commit%20Hook%0A%20%20%20%20Linter-%3E%3ELinter%3A%20Parse%20markdown%20files%20into%20AST%0A%20%20%20%20Linter-%3E%3ELinter%3A%20Scan%20AST%20Nodes%20for%20blocked%20keywords%0A%20%20%20%20alt%20Security%20violation%20detected%0A%20%20%20%20%20%20%20%20Linter--%3E%3EDeveloper%3A%20Exit%20code%201%20(Print%20error%20line%20and%20block%20commit)%0A%20%20%20%20else%20Validate%20OK%0A%20%20%20%20%20%20%20%20Linter--%3E%3EDeveloper%3A%20Exit%20code%200%20(Commit%20allowed)%0A%20%20%20%20end%0A"})]),fallback:a(()=>[...e[1]||(e[1]=[i(" Loading... ",-1)])]),_:1})),e[5]||(e[5]=o(`<hr><h2 id="_6-key-design-decisions" tabindex="-1">6. Key Design Decisions <a class="header-anchor" href="#_6-key-design-decisions" aria-label="Permalink to &quot;6. Key Design Decisions&quot;">​</a></h2><ul><li><strong>AST 기반 구문 스캔</strong>: 텍스트 파일 전체에 대해 무식하게 전체 정규식 스캔을 돌리는 대신, 마크다운 요소를 파싱하여 &quot;코드 블록 안의 내용&quot;, &quot;본문 제목&quot;, &quot;링크 주소&quot; 등으로 완벽하게 격리 노드화하여 탐지 오류(False Positive)를 혁신적으로 최소화했습니다.</li><li><strong>pre-commit 친화적 속도</strong>: Rust의 <code>pulldown-cmark</code> 파서를 사용해 개별 문서 분석 속도를 1ms 미만으로 극도로 줄여, 대용량 개발 문서가 담긴 저장소에서도 git commit 대기 지연을 유발하지 않도록 했습니다.</li></ul><h2 id="_7-security-considerations" tabindex="-1">7. Security Considerations <a class="header-anchor" href="#_7-security-considerations" aria-label="Permalink to &quot;7. Security Considerations&quot;">​</a></h2><ul><li>외부 네트워크 통신을 절대 수행하지 않고 로컬 CLI 오프라인 환경에서 모든 파일 내용 스캔 및 위반 사항 분석이 완결되어, 로컬 설계문서 내용이 외부 API를 타고 유출되는 것을 차단합니다.</li></ul><h2 id="_8-observability" tabindex="-1">8. Observability <a class="header-anchor" href="#_8-observability" aria-label="Permalink to &quot;8. Observability&quot;">​</a></h2><ul><li>기계 분석이 용이하도록 표준 에러 및 표준 출력을 통해 <code>JSON</code> 형식의 검사 리포트를 출력하여 CI/CD 파이프라인에서 오류 로그를 한눈에 파집할 수 있도록 지원합니다.</li></ul><h2 id="_9-technology-stack" tabindex="-1">9. Technology Stack <a class="header-anchor" href="#_9-technology-stack" aria-label="Permalink to &quot;9. Technology Stack&quot;">​</a></h2><ul><li><strong>Engine</strong>: Rust</li><li><strong>Parser Library</strong>: pulldown-cmark</li></ul><hr><h2 id="_10-running-locally" tabindex="-1">10. Running Locally <a class="header-anchor" href="#_10-running-locally" aria-label="Permalink to &quot;10. Running Locally&quot;">​</a></h2><p>로컬에서 임의의 문서 폴더를 지정해 린팅을 구동합니다.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># docs 디렉토리 내의 설계 초안 문서 검사</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">leandraft-linter</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./docs</span></span></code></pre></div><h2 id="_11-current-limitations" tabindex="-1">11. Current Limitations <a class="header-anchor" href="#_11-current-limitations" aria-label="Permalink to &quot;11. Current Limitations&quot;">​</a></h2><ul><li>이미지 파일 내부의 텍스트나 PDF 포맷 설계서에 대한 바이너리 스캔은 지원하지 않으며, 오직 텍스트 파일(Markdown, AsciiDoc)만 분석이 가능합니다.</li></ul><h2 id="_12-next-steps" tabindex="-1">12. Next Steps <a class="header-anchor" href="#_12-next-steps" aria-label="Permalink to &quot;12. Next Steps&quot;">​</a></h2><ul><li>기술 설계서 내부의 Mermaid 다이어그램 구문이 문법에 부합하는지 실시간 유효성을 체크해주는 Mermaid Linter 룰셋 탑재.</li></ul>`,17))])}const S=c(p,[["render",m]]);export{y as __pageData,S as default};
